    std::cerr << "[DEBUG] a=" << a << '\n';
    std::cerr << "[DEBUG] b=" << b << '\n';
    std::cerr << "[DEBUG] c=" << c << '\n';

    // Correct formula: parentheses ensure addition happens before division
    int average = (a + b + c) / 3;

    std::cout << "Average: " << average << '\n';

    return 0;
